iimagereader.interfaceCode:
interface IImageReader {
  /**
   * Lê uma imagem de uma fonte (caminho, URL ou Buffer)
   * @param source - Caminho do arquivo, URL ou Buffer da imagem
   * @returns Dados da imagem incluindo buffer, formato e dimensões
   */
  read(source: string | Buffer): Promise<ImageData>;

  /**
   * Verifica se o leitor suporta o formato especificado
   * @param format - Formato da imagem (png, jpg, gif, webp, svg, etc)
   */
  supports(format: string): boolean;
}

interface ImageData {
  buffer: Buffer;
  format: string;
  width: number;
  height: number;
  base64?: string;
}

iimageprocessor.interfaceCode:
interface IImageProcessor {
  /**
   * Redimensiona uma imagem mantendo aspect ratio
   */
  resize(image: ImageData, options: ResizeOptions): Promise<ImageData>;

  /**
   * Converte a imagem para outro formato
   */
  convert(image: ImageData, targetFormat: string): Promise<ImageData>;

  /**
   * Converte imagem para base64 string
   */
  toBase64(image: ImageData): Promise<string>;

  /**
   * Otimiza a imagem reduzindo tamanho sem perder muita qualidade
   */
  optimize(image: ImageData, quality?: number): Promise<ImageData>;
}

interface ResizeOptions {
  width?: number;
  height?: number;
  fit?: 'cover' | 'contain' | 'fill';
  maintainAspectRatio?: boolean;
}

imetadataextractor.interfaceCode:
interface IMetadataExtractor {
  /**
   * Extrai metadados de uma imagem
   */
  extract(image: ImageData): Promise<ImageMetadata>;

  /**
   * Verifica se a imagem contém metadados
   */
  hasMetadata(image: ImageData): Promise<boolean>;
}

interface ImageMetadata {
  exif?: ExifData;
  iptc?: IptcData;
  xmp?: XmpData;
  basic: {
    format: string;
    width: number;
    height: number;
    size: number;
    colorSpace?: string;
    hasAlpha?: boolean;
  };
}

interface ExifData {
  make?: string;
  model?: string;
  dateTime?: string;
  gps?: {
    latitude?: number;
    longitude?: number;
    altitude?: number;
  };
  camera?: {
    iso?: number;
    focalLength?: number;
    aperture?: number;
    shutterSpeed?: number;
  };
}

imcptool.interfaceCode:
interface IMCPTool {
  /**
   * Nome único do tool (snake_case)
   */
  name: string;

  /**
   * Descrição detalhada do que o tool faz
   */
  description: string;

  /**
   * JSON Schema para validação de parâmetros
   */
  inputSchema: {
    type: 'object';
    properties: Record<string, JSONSchemaProperty>;
    required?: string[];
  };

  /**
   * Handler que executa a lógica do tool
   */
  handler: (args: unknown) => Promise<MCPToolResponse>;
}

interface MCPToolResponse {
  content: Array<{
    type: 'text' | 'image' | 'resource';
    text?: string;
    data?: string;
    mimeType?: string;
  }>;
  isError?: boolean;
}

interface JSONSchemaProperty {
  type: string;
  description: string;
  enum?: string[];
  items?: JSONSchemaProperty;
  properties?: Record<string, JSONSchemaProperty>;
}
